#Here the goal is to find the number of Adenine, Thymine, Guanine and Cytosine in a given DNA_seq
DNA_seq=""
#separting the seq
bases=list(DNA_seq)
list={}
for base in bases:
    #check if base is already there or add it using if else
    if base in list:
        list[base]+=1
    else:
        list[base]=1
#printing result
for key, value in list.items():
    print(key,value)
